const AWS = require('aws-sdk');
const { execFile } = require('child_process');
const path = require('path');
const fs = require('fs');
const os = require('os');

const s3 = new AWS.S3();

exports.handler = async (event) => {
  const bucket = event.Records[0].s3.bucket.name;
  const key = decodeURIComponent(event.Records[0].s3.object.key.replace(/\+/g, ' '));
  const outputFormat = event.Records[0].s3.object.metadata.outputFormat;

  const tempDir = fs.mkdtempSync(path.join(os.tmpdir(), 'image-'));
  const inputFilePath = path.join(tempDir, path.basename(key));
  const outputFilePath = path.join(tempDir, `${path.basename(key, path.extname(key))}.${outputFormat}`);

  try {
    const params = { Bucket: bucket, Key: key };
    const inputData = await s3.getObject(params).promise();
    fs.writeFileSync(inputFilePath, inputData.Body);

    await new Promise((resolve, reject) => {
      execFile('convert', [inputFilePath, outputFilePath], (error) => {
        if (error) {
          reject(`ImageMagick convert error: ${error}`);
        } else {
          resolve();
        }
      });
    });

    const outputData = fs.readFileSync(outputFilePath);
    const outputKey = `${path.basename(key, path.extname(key))}.${outputFormat}`;
    await s3.putObject({
      Bucket: bucket,
      Key: outputKey,
      Body: outputData,
      ContentType: `image/${outputFormat}`
    }).promise();

    return { status: 'Image converted successfully', outputKey };
  } catch (error) {
    console.error('Error processing image:', error);
    throw new Error('Image processing failed');
  } finally {
    fs.unlinkSync(inputFilePath);
    fs.unlinkSync(outputFilePath);
    fs.rmdirSync(tempDir);
  }
};